real_t s172(struct args_t * func_args)
{
    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    real_t * __restrict__ a_res = a;
    real_t * __restrict__ b_res = b;

    for (int nl = 0; nl < iterations; nl++) {
        int start = n1 - 1;
        int stride = n3;

        if (stride == 1) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i++) {
                a_res[i] += b_res[i];
            }
        } else if (stride == 2) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i += 2) {
                a_res[i] += b_res[i];
            }
        } else if (stride == 4) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i += 4) {
                a_res[i] += b_res[i];
            }
        } else {
            for (int i = start; i < LEN_1D; i += stride) {
                a_res[i] += b_res[i];
            }
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s1113(struct args_t * func_args)
{

//    linear dependence testing
//    one iteration dependency on a(LEN_1D/2) but still vectorizable

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < 2*iterations; nl++) {
        int mid = LEN_1D / 2;

        // Phase 1: i < mid
        // a[mid] is not written yet, safe to read and vectorize
        #pragma clang loop vectorize(enable)
        for (int i = 0; i < mid; i++) {
            a[i] = a[mid] + b[i];
        }

        // Phase 2: i == mid
        // Read the original a[mid] (which is still valid here) and write it
        a[mid] = a[mid] + b[mid];

        // Phase 3: i > mid
        // a[mid] has been updated, subsequent iterations read the new value
        #pragma clang loop vectorize(enable)
        for (int i = mid + 1; i < LEN_1D; i++) {
            a[i] = a[mid] + b[i];
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s122(struct args_t * func_args)
{

//    induction variable recognition
//    variable lower and upper bound, and stride
//    reverse data access and jump in data access

    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    int j, k;
    int start = n1 - 1;
    int stride = n3;

    // Helper array for precomputing indices
    // LEN_1D is the maximum possible number of iterations
    static int k_vals[LEN_1D];

    for (int nl = 0; nl < iterations; nl++) {
        j = 1;
        k = 0;

        if (stride == 1) {
            // Fast path for stride 1: direct vectorization
            // k follows sequence 1, 2, 3... relative to loop start
            // k = (i - start) + 1
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i++) {
                int current_k = (i - start) + 1;
                a[i] += b[LEN_1D - current_k];
            }
        } else {
            // Generic path: two-phase approach
            // Phase 1: Precompute k values
            int idx = 0;
            for (int i = start; i < LEN_1D; i += stride) {
                k += j;
                k_vals[idx++] = k;
            }

            // Phase 2: Vectorized data access using precomputed indices
            #pragma clang loop vectorize(enable)
            for (int t = 0; t < idx; t++) {
                int i = start + t * stride;
                a[i] += b[LEN_1D - k_vals[t]];
            }
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}
